}

if (process.env["NODE_ENV"] === "production") {
  try {
    await runMigrations();
  } catch (err) {
    logger.error({ err }, "Migration failed — aborting startup");
    process.exit(1);
  }
}

// Warn if MP_WEBHOOK_SECRET is not set — without it anyone can trigger subscription activation
