    staleTime: 60_000,
    retry: (failCount, err) => {
      const msg = (err as Error)?.message ?? "";
      if (msg.startsWith("401") || msg.startsWith("403") || msg.includes("HTTP 401") || msg.includes("HTTP 403")) return false;
      return failCount < 2;
    },
